def clean_leads_data(validated_data):
    df = pd.DataFrame(validated_data)

    # 1. 去重
    df = df.drop_duplicates(subset=['lead_id'], keep='first')

    # 2. 清洗联系方式
    def clean_contact(contact):
        if pd.isna(contact):
            return None
        contact_str = str(contact)
        # 提取数字
        numbers = re.findall(r'\d+', contact_str)
        if numbers:
            return ''.join(numbers)[-11:]  # 取最后11位作为手机号
        return None

    df['cleaned_contact'] = df['contact'].apply(clean_contact)

    # 3. 标准化预算字段
    def parse_budget(budget):
        if pd.isna(budget):
            return 0.0
        if isinstance(budget, (int, float)):
            return float(budget)
        budget_str = str(budget)
        # 移除货币符号和逗号
        budget_str = re.sub(r'[^\d.]', '', budget_str)
        try:
            return float(budget_str) if budget_str else 0.0
        except:
            return 0.0

